html: <!DOCTYPE html> <html lang="en"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title>Accessible Tree View</title> <link rel="stylesheet" href="styles.css"> </head> <body> <div id="tree-view" role="tree" aria-label="Tree View">   <ul role="group" aria-label="Root Node">     <li role="treeitem" aria-label="Node 1" tabindex="0">       <span role="presentation" class="px-2 py-1">Node 1</span>       <ul role="group" aria-label="Subnode 1">         <li role="treeitem" aria-label="Subnode 1.1" tabindex="0">           <span role="presentation" class="px-2 py-1">Subnode 1.1</span>         </li>         <li role="treeitem" aria-label="Subnode 1.2" tabindex="0">           <span role="presentation" class="px-2 py-1">Subnode 1.2</span>         </li>       </ul>     </li>     <li role="treeitem" aria-label="Node 2" tabindex="0">       <span role="presentation" class="px-2 py-1">Node 2</span>     </li>   </ul> </div> <script src="script.js"></script> </body> </html>
css: @tailwind base; @tailwind components; @tailwind utilities; .tree-view {   list-style: none;   padding: 0;   margin: 0; } .tree-view ul {   padding: 0;   list-style: none; } .tree-view li {   padding: 10px;   border-bottom: 1px solid #ccc; } .tree-view li:last-child {   border-bottom: none; } .tree-view .node-selected {   background-color: #ddd;   color: #333; }
js: const tree = document.getElementById("tree-view"); const nodes = tree.querySelectorAll("li[role='treeitem']"); let currentNodeIndex = 0; nodes.forEach((node, index) => {   node.addEventListener("keydown", (e) => {     if (e.key === "ArrowRight") {       toggleNode(node);     } else if (e.key === "ArrowLeft") {       if (nodes[currentNodeIndex].querySelector("ul") !== null) {         toggleNode(nodes[currentNodeIndex]);       }     }     if (e.key === "ArrowDown") {       if (nodes[currentNodeIndex].querySelector("ul") !== null) {         let nextNodeIndex = currentNodeIndex + 1;         if (nextNodeIndex >= nodes.length) {           nextNodeIndex = 0;         }         selectNode(nodes[nextNodeIndex]);       }     } else if (e.key === "ArrowUp") {       if (nodes[currentNodeIndex].querySelector("ul") !== null) {         let nextNodeIndex = currentNodeIndex - 1;         if (nextNodeIndex < 0) {           nextNodeIndex = nodes.length - 1;         }         selectNode(nodes[nextNodeIndex]);       }     }   }); }); function selectNode(node) {   nodes.forEach((n) => n.classList.remove("node-selected"));   node.classList.add("node-selected");   currentNodeIndex = nodes.indexOf(node);} function toggleNode(node) {   let subnode = node.querySelector("ul");   if (subnode !== null) {     if (subnode.style.display === "none") {       subnode.style.display = "block";     } else {       subnode.style.display = "none";     }   }}
